mapper.select:
SELECT ea.*, er.roomName, er.roomLocation
FROM exam_arrange ea
LEFT JOIN exam_room er ON ea.roomId = er.roomId
WHERE ea.roomId = #{roomId}
AND ea.arrangeDate = #{date}
ORDER BY ea.session

mapper.update:
UPDATE exam_arrange
SET assignedSeats = assignedSeats + #{increment}
WHERE arrangeId = #{arrangeId}

INSERT INTO exam_arrange (examCode, roomId, arrangeDate, session, totalSeats, assignedSeats, status)
SELECT #{examCode}, roomId, #{date}, #{session}, #{studentCount}, 0, '0'
FROM exam_room
WHERE roomCapacity >= #{studentCount}
AND availableSeats >= #{studentCount}
AND status = '0'
AND roomId NOT IN (
    SELECT DISTINCT roomId
    FROM exam_arrange
    WHERE arrangeDate = #{date}
    AND session = #{session}
    AND status IN ('1', '2')
)
LIMIT 1

mapper.select:
SELECT COUNT(*)
FROM exam_arrange
WHERE roomId = #{roomId}
AND arrangeDate = #{date}
AND session = #{session}
AND arrangeId != #{excludeArrangeId}
AND status IN ('1', '2')
